#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=100005;
int n,a[N][5],dp[N][5][5],ans;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i][0]>>a[i][1]>>a[i][2];
	}
	for(int i=0;i<3;i++)
	{
		memset(dp,0,sizeof(dp));
		dp[1][i][0]=dp[1][i][1]=a[1][i];
		for(int j=2;j<=n;j++)
		{
			dp[j][0][0]=max(dp[j-1][1][1],dp[j-1][2][1])+a[j][0];
			dp[j][1][0]=dp[j-1][2][1]+a[j][1];
			dp[j][1][1]=dp[j-1][0][0]+a[j][1];
			dp[j][2][1]=max(dp[j-1][1][0],dp[j-1][0][0])+a[j][2];
		}
		for(int j=0;j<i;j++) ans=max(ans,dp[n][j][0]);
		for(int j=2;j>i;j--) ans=max(ans,dp[n][j][1]);
	}
	cout<<ans;
	return 0;
}
